/**
 * Component Parameter Schema Types
 *
 * These types match the JSON Schema format generated by the okapi-bridge
 * schema generator and the Go schema.FromStruct() reflection helper,
 * with x-* extensions for UI rendering.
 *
 * Both filters and tools use the same schema format. FilterSchema is a
 * specialization of ComponentSchema with filter-specific metadata.
 */

/** Generalized component schema — works for both filters and tools. */
export interface ComponentSchema {
  $id: string;
  $version?: string;
  title: string;
  description?: string;
  type: string;
  "x-component"?: ComponentMeta;
  "x-filter"?: FilterMeta;
  "x-groups"?: ParameterGroup[];
  "x-apiVersion"?: string;
  "x-introducedInOkapi"?: string;
  properties: Record<string, PropertySchema>;
  $defs?: Record<string, PropertySchema>;
}

/** Component metadata (for tools, steps, etc.) */
export interface ComponentMeta {
  id: string;
  type: string; // "format" | "tool" | "step"
  category?: string; // "transform" | "validate" | "enrich" | "convert" | "pipeline"
  displayName?: string;
  description?: string;
}

/** Filter-specific schema (backward compatible specialization). */
export interface FilterSchema extends ComponentSchema {
  "x-filter": FilterMeta;
}

export interface FilterMeta {
  id: string;
  class: string;
  extensions: string[];
  mimeTypes: string[];
  serializationFormat?: "stringParameters" | "yaml" | "xml-its";
  configurations?: FilterConfiguration[];
}

export interface FilterConfiguration {
  configId: string;
  name: string;
  description?: string;
  parameters?: Record<string, unknown>;
  isDefault?: boolean;
}

export interface ParameterGroup {
  id: string;
  label: string;
  description?: string;
  collapsed?: boolean;
  fields: string[];
}

export interface PropertySchema {
  type: string;
  description?: string;
  default?: unknown;
  deprecated?: boolean;
  enum?: string[];
  title?: string;
  minimum?: number;
  maximum?: number;

  // Nested object properties
  properties?: Record<string, PropertySchema>;
  additionalProperties?: PropertySchema | boolean;
  items?: PropertySchema;
  required?: string[];
  $ref?: string;

  // UI hints (x-* extensions)
  "x-widget"?: WidgetType;
  "x-placeholder"?: string;
  "x-presets"?: Record<string, unknown>;
  "x-okapiFormat"?: string;
  "x-order"?: number;
  "x-showIf"?: ShowIfCondition;
  /** Structured UI editor metadata from Okapi EditorDescription. */
  "x-editor"?: EditorMeta;
  /** Display labels for enum values, keyed by enum value. */
  "x-enumLabels"?: Record<string, string>;
  /** Descriptions for enum values, keyed by enum value. */
  "x-enumDescriptions"?: Record<string, string>;
  /** Original Okapi parameter name when schema uses a cleaner name. */
  "x-flattenPath"?: string;
  /** Okapi version where this parameter was introduced. */
  "x-introducedInOkapi"?: string;
}

/** Structured UI editor metadata from x-editor. */
export interface EditorMeta {
  widget: string;
  enabledBy?: {
    parameter: string;
    enabledWhenSelected: boolean;
  };
  layout?: {
    withLabel?: boolean;
    vertical?: boolean;
  };
  text?: { password?: boolean; allowEmpty?: boolean; height?: number };
  path?: {
    browseTitle?: string;
    forSaveAs?: boolean;
    allowEmpty?: boolean;
    filters?: Array<{ name: string; extensions: string }>;
  };
  folder?: { browseTitle?: string };
  checkList?: { entries: Array<{ name: string; title: string; description?: string }> };
}

export type WidgetType =
  | "regexBuilder"
  | "codeFinderRules"
  | "tagList"
  | "numberList"
  | "simplifierRulesEditor"
  | "filterSelector"
  | "elementRulesEditor"
  | "attributeRulesEditor"
  | "code-editor";

export interface ShowIfCondition {
  field: string;
  value: unknown;
}

/**
 * CodeFinderRules value structure (clean JSON format).
 */
export interface CodeFinderRulesValue {
  rules: Array<{ pattern: string }>;
  sample?: string;
  useAllRulesWhenTesting?: boolean;
}

/**
 * Filter parameters value type.
 */
export type FilterParamsValue = Record<string, unknown>;
